          "LANG", "LC_ALL", "LC_CTYPE", "LC_MESSAGES", "TERM",
          "NODE_ENV", "NIX_PATH",
          "REPL_HOME", "REPL_ID", "REPL_OWNER", "REPL_SLUG",
