      // so a malformed date can't leak into the builder's date math.
      const isYmd = (s: unknown): s is string => typeof s === "string" && /^\d{4}-\d{2}-\d{2}$/.test(s.trim());
      const given = (s: unknown) => s !== undefined && s !== null && String(s).trim() !== "";
